#include <bits/stdc++.h>
using namespace std;

int a[100010];
struct m{
    int a;
    int i;
};

int main(){
    int n,s=0;
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    m m1,m2;
    for(int i=1;i<n;i++){
        m1.a=2147483647;
        m2.a=2147483647;
        for(int j=1;j<=n;j++)
        {
            if(a[j]!=-1)
            {
                if(a[j]<m1.a){
                    m1.a=a[j];
                    m1.i=j;
                }
                if(a[j]<m2.a){
                    m2.a=a[j];
                    m2.i=j;
                }
            }
        }
        s=s+m1.a+m2.a;
        a[m1.i]=m1.a+m2.a;
        a[m2.i]=-1;
    }
    cout<<s;
    return 0;
}
